    categoryName: "Ortodonzia",
    keywords: ["morso aperto anteriore", "intrusione molare TAD", "iperdivergenza mandibolare", "MAA scheletrico", "griglia antilinguale", "Le Fort I impaction", "recidiva morso aperto"],
    publishedAt: "2026-02-02",
    readTime: 24
